In C++, you can declare a class using the `class` keyword. Here's an example:

```cpp
class MyClass {
  private:
    int myNumber;
    string myString;

  public:
    // Default constructor
    MyClass() {
      myNumber = 0;
      myString = "";
    }

    // Parameterized constructor
    MyClass(int number, string text) {
      myNumber = number;
      myString = text;
    }

    // Member function
    void printData() {
      cout << "Number: " << myNumber << ", String: " << myString << endl;
    }
};
```

In the above example, `MyClass` is a class with two private member variables (`myNumber` and `myString`). It has two constructors - a default constructor that initializes the member variables with default values, and a parameterized constructor that allows you to set values for the member variables during object initialization. It also has a member function `printData()` that prints the values of the member variables.

To create objects of this class, you can do the following:

```cpp
// Create an object using default constructor
MyClass obj1;

// Create an object using parameterized constructor
MyClass obj2(10, "Hello");

// Call member function
obj1.printData(); // Output: Number: 0, String: 
obj2.printData(); // Output: Number: 10, String: Hello
```

Here, `obj1` is created using the default constructor, so `myNumber` is 0 and `myString` is an empty string. `obj2` is created using the parameterized constructor, with `myNumber` as 10 and `myString` as "Hello".

In C++, you can declare and use vectors by including the `<vector>` header file. Vectors are dynamic arrays that can resize themselves. Here are some implementation examples:

1. Declaring a vector:
```cpp
#include <vector>
using namespace std;

vector<int> numbers; // Declaring a vector of integers
vector<string> names; // Declaring a vector of strings
```

2. Initializing a vector with values:
```cpp
#include <vector>
using namespace std;

vector<int> numbers = {10, 20, 30, 40, 50}; // Initializing a vector with integers
vector<string> names = {"John", "Jane", "Alice"}; // Initializing a vector with strings
```

3. Adding elements to a vector:
```cpp
#include <vector>
using namespace std;

vector<int> numbers;

numbers.push_back(10); // Adding an integer to the vector
numbers.push_back(20);
numbers.push_back(30);
```

4. Accessing vector elements:
```cpp
#include <vector>
using namespace std;

vector<int> numbers = {10, 20, 30, 40, 50};

int firstElement = numbers[0]; // Accessing the first element
int secondElement = numbers.at(1); // Accessing the second element using the at() function

// Iterating over the vector
for (int i = 0; i < numbers.size(); i++) {
    cout << numbers[i] << " ";
}
```

5. Modifying vector elements:
```cpp
#include <vector>
using namespace std;

vector<int> numbers = {10, 20, 30, 40, 50};

numbers[2] = 35; // Modifying the third element
numbers.at(4) = 55; // Modifying the fifth element using the at() function
```

6. Removing elements from a vector:
```cpp
#include <vector>
using namespace std;

vector<int> numbers = {10, 20, 30, 40, 50};

numbers.pop_back(); // Removing the last element

// Removing a specific element by value
vector<int>::iterator it = find(numbers.begin(), numbers.end(), 30);
if (it != numbers.end()) {
    numbers.erase(it);
}
```

These are some basic operations you can perform on vectors in C++. You can explore more vector functions and operations in the C++ documentation.

Sure! Here are examples of declaring data structures in C++ for a linked list, binary tree, and hash table:

1. Linked List:
```cpp
#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* next;
};

class LinkedList {
private:
    Node* head;

public:
    LinkedList() {
        head = nullptr;
    }

    void insert(int value) {
        Node* newNode = new Node;
        newNode->data = value;
        newNode->next = nullptr;

        if (head == nullptr) {
            head = newNode;
        } else {
            Node* temp = head;
            while (temp->next != nullptr) {
                temp = temp->next;
            }
            temp->next = newNode;
        }
    }

    void display() {
        Node* temp = head;
        while (temp != nullptr) {
            cout << temp->data << " ";
            temp = temp->next;
        }
        cout << endl;
    }
};
```

2. Binary Tree:
```cpp
#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* left;
    Node* right;
};

class BinaryTree {
private:
    Node* root;

public:
    BinaryTree() {
        root = nullptr;
    }

    void insert(int value) {
        Node* newNode = new Node;
        newNode->data = value;
        newNode->left = nullptr;
        newNode->right = nullptr;

        if (root == nullptr) {
            root = newNode;
        } else {
            Node* temp = root;
            while (temp != nullptr) {
                if (value < temp->data) {
                    if (temp->left == nullptr) {
                        temp->left = newNode;
                        break;
                    } else {
                        temp = temp->left;
                    }
                } else {
                    if (temp->right == nullptr) {
                        temp->right = newNode;
                        break;
                    } else {
                        temp = temp->right;
                    }
                }
            }
        }
    }

    void displayInOrder(Node* node) {
        if (node != nullptr) {
            displayInOrder(node->left);
            cout << node->data << " ";
            displayInOrder(node->right);
        }
    }

    void display() {
        displayInOrder(root);
        cout << endl;
    }
};
```

3. Hash Table:
```cpp
#include <iostream>
#include <unordered_map>
using namespace std;

class HashTable {
private:
    unordered_map<int, int> table;

public:
    void insert(int key, int value) {
        table[key] = value;
    }

    int get(int key) {
        if (table.find(key) != table.end()) {
            return table[key];
        } else {
            return -1;
        }
    }

    void remove(int key) {
        if (table.find(key) != table.end()) {
            table.erase(key);
        }
    }
};
```

Note that these are just basic implementations to demonstrate the declaration of each data structure. In practice, you would need to implement additional functionality and error checks for each data structure.
